type Queue struct {
	elements []int
}

func (q *Queue) PushBack(userID int) {
	q.elements = append(q.elements, userID)
}

func (q *Queue) PushFront(userID int) {
	q.elements = append([]int{userID}, q.elements...)
}

func (q *Queue) Pop() (int, bool) {
	if len(q.elements) == 0 {
		return 0, false
	}
	userID := q.elements[0]
	q.elements = q.elements[1:]
	return userID, true
}

