public class LargestSumNonConsecutive {
    public int maxSum(int[] nums) {
        return maxSumUtil(nums, nums.length - 1, new HashMap<>());
    }

    private int maxSumUtil(int[] nums, int index, HashMap<Integer, Integer> cache) {
        if (index < 0) return 0;
        if (cache.containsKey(index)) return cache.get(index);

        int include = nums[index] + maxSumUtil(nums, index - 2, cache);
        int exclude = maxSumUtil(nums, index - 1, cache);
        int result = Math.max(include, exclude);

        cache.put(index, result);
        return result;
    }
}
